# Notes:
# - Keep the given function signature unchanged.
# - Use only the Python standard library; no third-party packages.
# - Do not change input/output formats or return value semantics as defined by the template/problem.
# - Conformance: use features compatible with LeetCode’s Python3 runtime; do NOT rely on undefined/implementation-specific behavior.
# - If you introduce any helper functions/classes, include their full implementations in this file; no hidden helpers.

class Solution(object):
    def minSizeSubarray(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: int
        """
        n = len(nums)
        total_sum = sum(nums)
        min_length = float('inf')

        # Check if the target can be achieved by repeating the array
        if total_sum == 0:
            return -1 if target != 0 else 1

        # Check for subarrays in the original array
        current_sum = 0
        left = 0
        for right in range(n):
            current_sum += nums[right]
            while current_sum > target and left <= right:
                current_sum -= nums[left]
                left += 1
            if current_sum == target:
                min_length = min(min_length, right - left + 1)

        # Check for subarrays that wrap around the end of the array
        if total_sum > 0:
            for i in range(n):
                current_sum += nums[i]
                while current_sum > target and left <= i:
                    current_sum -= nums[left]
                    left += 1
                if current_sum == target:
                    min_length = min(min_length, i - left + 1)

        return min_length if min_length != float('inf') else -1